14→    fun archiveThreads(messages: List<MessageReference>) {
15→        archiveByFolder("archiveThreads", messages) { account, folderId, messagesInFolder, archiveFolderId ->
16→            archiveThreads(account, folderId, messagesInFolder, archiveFolderId)
17→        }
18→    }
19→
20→    fun archiveMessages(messages: List<MessageReference>) {
21→        archiveByFolder("archiveMessages", messages) { account, folderId, messagesInFolder, archiveFolderId ->
22→            archiveMessages(account, folderId, messagesInFolder, archiveFolderId)
23→        }
24→    }
25→
26→    fun archiveMessage(message: MessageReference) {
27→        archiveMessages(listOf(message))
28→    }
